('room_s0290', 'user2', 2, '사진보다 조금 낡은 느낌이라 아쉬웠어요.', DATE_ADD(NOW(), INTERVAL 171 MINUTE)),
('room_s0290', 'user1', 2, '냄새가 좀 나서 환기를 자주 해야 했어요. 관리비는 평균 수준입니다.', DATE_ADD(NOW(), INTERVAL 438 MINUTE)),
('room_s0291', 'user2', 4, '옵션이 알차고 전반적으로 만족합니다.', DATE_ADD(NOW(), INTERVAL 531 MINUTE)),
('room_s0291', 'user1', 5, '입주 전 청소가 잘 되어 있었고, 가구/가전 상태도 전반적으로 양호했습니다. 특히 수압이 좋아서 샤워할 때 불편함이 없었어요. 공용주방도 주기적으로 관리되는 느낌이라 만족합니다.', DATE_ADD(NOW(), INTERVAL 373 MINUTE)),
('room_s0292', 'user2', 5, '사진이랑 실물이 거의 같았어요. 추천합니다. 관리비는 평균 수준입니다.', DATE_ADD(NOW(), INTERVAL 92 MINUTE)),
('room_s0292', 'user1', 5, '출퇴근 동선이 좋아서 선택했는데 정말 편해요. 주변에 편의점/카페가 많고, 밤에도 비교적 안전한 분위기입니다. 관리비 내역도 투명하게 안내해줘서 신뢰가 갔습니다.', DATE_ADD(NOW(), INTERVAL 471 MINUTE)),
('room_s0293', 'user1', 3, '위치는 좋은데 수납이 생각보다 적어요.', DATE_ADD(NOW(), INTERVAL 81 MINUTE)),
('room_s0293', 'user2', 5, '채광이 좋아서 식물 키우기에도 좋고, 방음도 생각보다 괜찮습니다. 공용 라운지가 넓어서 재택할 때도 집중이 잘 돼요. 다음에 이사해도 비슷한 곳으로 가고 싶습니다.', DATE_ADD(NOW(), INTERVAL 432 MINUTE)),
('room_s0294', 'user2', 3, '가격 대비 무난합니다. 큰 불만은 없어요.', DATE_ADD(NOW(), INTERVAL 611 MINUTE)),
('room_s0294', 'user1', 3, '위치는 좋은데 수납이 생각보다 적어요.', DATE_ADD(NOW(), INTERVAL 495 MINUTE)),
('room_s0295', 'user1', 5, '사진이랑 실물이 거의 같았어요. 추천합니다.', DATE_ADD(NOW(), INTERVAL 696 MINUTE)),
('room_s0295', 'user2', 4, '엘리베이터 대기가 가끔 길어요. 가성비 괜찮아요.', DATE_ADD(NOW(), INTERVAL 304 MINUTE)),
('room_s0296', 'user1', 5, '채광이 좋아서 식물 키우기에도 좋고, 방음도 생각보다 괜찮습니다. 공용 라운지가 넓어서 재택할 때도 집중이 잘 돼요. 다음에 이사해도 비슷한 곳으로 가고 싶습니다.', DATE_ADD(NOW(), INTERVAL 127 MINUTE)),
('room_s0296', 'user2', 1, '사진에서 기대했던 것보다 시설이 노후된 느낌이었습니다. 하자도 몇 군데 있었고 안내가 부족했어요. 다시 선택하라면 고민할 것 같습니다. 환기만 잘하면 좋아요.', DATE_ADD(NOW(), INTERVAL 523 MINUTE)),
('room_s0297', 'user1', 3, '엘리베이터 대기가 가끔 길어요.', DATE_ADD(NOW(), INTERVAL 250 MINUTE)),
('room_s0297', 'user2', 4, '주변이 밤에 조금 시끄럽습니다. 가성비 괜찮아요.', DATE_ADD(NOW(), INTERVAL 578 MINUTE)),
('room_s0298', 'user1', 5, '사진이랑 실물이 거의 같았어요. 추천합니다. 관리비는 평균 수준입니다.', DATE_ADD(NOW(), INTERVAL 70 MINUTE)),
('room_s0298', 'user2', 5, '층간소음이 거의 없고 조용해요. 재방문 의사 있어요.', DATE_ADD(NOW(), INTERVAL 514 MINUTE)),
('room_s0299', 'user1', 5, '입주 전 청소가 잘 되어 있었고, 가구/가전 상태도 전반적으로 양호했습니다. 특히 수압이 좋아서 샤워할 때 불편함이 없었어요. 공용주방도 주기적으로 관리되는 느낌이라 만족합니다.', DATE_ADD(NOW(), INTERVAL 506 MINUTE)),
('room_s0299', 'user2', 5, '입주 전 청소가 잘 되어 있었고, 가구/가전 상태도 전반적으로 양호했습니다. 특히 수압이 좋아서 샤워할 때 불편함이 없었어요. 공용주방도 주기적으로 관리되는 느낌이라 만족합니다.', DATE_ADD(NOW(), INTERVAL 501 MINUTE)),
('room_s0300', 'user2', 5, '층간소음이 거의 없고 조용해요.', DATE_ADD(NOW(), INTERVAL 443 MINUTE)),
('room_s0300', 'user1', 5, '역이랑 가까워서 출퇴근이 편합니다.', DATE_ADD(NOW(), INTERVAL 473 MINUTE));
